我给你展示下面的关于reward 函数的计算代码，然后请回答一个问题，现在我想修改compute_reward函数，其输入需要额外一个新的变量那就是prompt，请问我该从哪里入手把这个变量加进去：geo3k_judger_config = GEO3KJudgerConfig()
judger_cfg = JudgerConfig(reward_judger_configs=[geo3k_judger_config]) def compute_reward(response: str, label: str, extra_info: Dict[str, Any]) -> Dict[str, float]:
    format_score = float(extra_info.get("format_score", 0.1))
    use_boxed = bool(extra_info.get("use_boxed", True))
    question_type = extra_info.get("question_type", "auto")

    acc = acc_reward(response, label, use_boxed=use_boxed, question_type=question_type)
    fmt = format_reward(response, question_type=question_type, ground_truth=label)

    # 修复 bug：补上乘号
    score = (1.0 - format_score) _acc + format_score_ fmt

    return {"score": float(score), "acc": float(acc), "format": float(fmt)}


class GEO3KJudgerConfig(NativeJudgerConfig):
    judger_name: str = "hiyouga/geometry3k"
    extra_info: dict = {
        "format_score": 0.1,
        "use_boxed": True,
        "question_type": "auto",
    }
    reward_func: Callable = compute_reward   class JudgerConfig(BaseModel):
    """Judger configuration for XTuner.

    Configuration for the judging system managing batch processing and custom judger
    implementations for model evaluation and reward computation.

    Args:
        enable_batch_reward (bool): Enable calculate reward within the data group of repeat_prompt_k. Defaults to False.

        reward_judger_configs (Dict[str, BaseModel]): Dictionary mapping judger names
            to their configuration objects. We provided the example GSM8KJudgerConfig
            for GSM8K mathematical reasoning tasks (see ``xtuner/v1/ray/judger/gsm8k.py``). Defaults to empty dict.

    **Examples:**

        Example configuration for single judger::

            config = JudgerConfig(
                enable_batch_reward=False,
                reward_judger_configs={
                    "gsm8k": GSM8KJudgerConfig(...)
                }
            )

        Example configuration for multiple judgers::

            config = JudgerConfig(
                reward_judger_configs={
                    "gsm8k": GSM8KJudgerConfig(...),
                    "math_qa": MathQAJudgerConfig(...),
                    "custom_eval": CustomJudgerConfig(...)
                }
            )

    .. note::
        You should ensure each dataset item specifies data_source with dictionary mapping judger names to their weight ratios

        Example dataset item::

            data_item = {
                "data_source": {"gsm8k": 0.7, "math_qa": 0.3},
                "response_str": "...",
                "reward_model": {"ground_truth": "..."}
            }
    """

    model_config = ConfigDict(extra="forbid")

    enable_batch_reward: Annotated[
        bool, Parameter(help="Whether to enable batch reward calculation for multiple samples at once.")
    ] = False
    enable_weighted_judgers: Annotated[
        bool, Parameter(help="Whether to enable weighted reward calculation on multi judgers.")
    ] = False
    reward_judger_configs: Annotated[
        List[NativeJudgerConfig],
        Parameter(help="A custom Python function for computing reward given model output and label."),
    ] = []
    judger_timeout: Annotated[float, Parameter(help="Timeout for each judger request in seconds.")] = 1200.0
    worker_log_dir: Annotated[Path, Parameter(help="Directory to save worker logs.")] = Path.cwd() / "work_dir"

    @computed_field
    def total_bundles_needed(self) -> list[dict]:
        judger_total_bundles = [
            {"CPU": cfg.num_cpus_per_actor, "memory": cfg.num_cpus_per_actor _1024_*3}
            for cfg in self.reward_judger_configs
            for _in range(cfg.num_ray_actors)
        ]
        return judger_total_bundles

    @computed_field
    def total_cpus_needed(self) -> int:
        judger_total_cpus = sum(cfg.num_cpus_per_actor * cfg.num_ray_actors for cfg in self.reward_judger_configs)
        return judger_total_cpus

    @computed_field
    def total_memory_needed(self) -> int:
        judger_total_memory = sum(
            cfg.num_cpus_per_actor _1024_*3 * cfg.num_ray_actors for cfg in self.reward_judger_configs
        )
        return judger_total_memory
